using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removes "Discriminator" property from
            // non-hierarchical containers. Existing documents still have it,
            // so we must opt back in to read them.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: EF 9 uses only the raw key for "id"
            // (e.g. "1") instead of "Blog|1". Opt in to the legacy format
            // so existing documents are still found.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined
            // via EF Core's HasIndex. EF 9 now throws instead of silently
            // ignoring it. Remove the HasIndex call.
            // (HasIndex removed — was: entity.HasIndex(b => b.Name))
        });
    }
}

